141â†’internal class OptionalFormatStructure<in T>(
142â†’    val onZero: String,
143â†’    val format: FormatStructure<T>,
144â†’) : NonConcatenatedFormatStructure<T> {
145â†’    override fun toString(): String = "Optional($onZero, $format)"
146â†’
147â†’    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148â†’        PropertyWithDefault.fromField(field)
149â†’    }
150â†’
151â†’    override fun equals(other: Any?): Boolean =
152â†’        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153â†’
154â†’    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155â†’
156â†’    override fun parser(): ParserStructure<T> = ParserStructure(
157â†’        operations = emptyList(),
158â†’        followedBy = listOf(
159â†’            format.parser(),
160â†’            listOf(
161â†’                ConstantFormatStructure<T>(onZero).parser(),
162â†’                ParserStructure(
163â†’                    listOf(
164â†’                        UnconditionalModification {
165â†’                            for (field in fields) {
166â†’                                field.assignDefault(it)
167â†’                            }
168â†’                        }
169â†’                    ),
170â†’                    emptyList()
171â†’                )
172â†’            ).concat()
173â†’        )
174â†’    )
175â†’
176â†’    override fun formatter(): FormatterStructure<T> {
177â†’        val formatter = format.formatter()
178â†’        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179â†’        return ConditionalFormatter(
180â†’            listOf(
181â†’                predicate::test to ConstantStringFormatterStructure(onZero),
182â†’                Truth::test to formatter
183â†’            )
184â†’        )
185â†’    }
186â†’
187â†’    private class PropertyWithDefault<in T, E> private constructor(
188â†’        private val accessor: Accessor<T, E>,
189â†’        private val defaultValue: E
190â†’    ) {
191â†’        companion object {
192â†’            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
193â†’                val default = field.defaultValue
194â†’                require(default != null) {
195â†’                    "The field '${field.name}' does not define a default value"
196â†’                }
197â†’                return PropertyWithDefault(field.accessor, default)
198â†’            }
199â†’        }
200â†’
201â†’        inline fun assignDefault(target: T) {
202â†’            accessor.trySetWithoutReassigning(target, defaultValue)
203â†’        }
204â†’
205â†’        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
206â†’    }
207â†’}
