  8â†’import kotlin.jvm.JvmInline
  9â†’
 10â†’/**
 11â†’ * Describes the commands that the parser must execute, in two portions:
 12â†’ * * [operations], which are executed in order, and
 13â†’ * * [followedBy], which are executed *in parallel* after [operations].
 14â†’ *
 15â†’ * An example of a [ParserStructure]:
 16â†’ * ```
 17â†’ * // number - dash - number - dash - number
 18â†’ * //        |
 19â†’ * //        \
 20â†’ * //         letter 'W' - number
 21â†’ * ParserStructure(
 22â†’ *   listOf(numberParser),
 23â†’ *   listOf(
 24â†’ *     ParserStructure(
 25â†’ *       listOf(stringParser("-"), numberParser, stringParser("-"), numberParser),
 26â†’ *       emptyList()
 27â†’ *     ),
 28â†’ *     ParserStructure(
 29â†’ *       listOf(stringParser("W"), numberParser),
 30â†’ *       emptyList()
 31â†’ *     ),
 32â†’ *   )
 33â†’ * )
 34â†’ * ```
 35â†’ */
 36â†’internal class ParserStructure<in Output>(
 37â†’    val operations: List<ParserOperation<Output>>,
 38â†’    val followedBy: List<ParserStructure<Output>>,
 39â†’) {
 40â†’    override fun toString(): String =
 41â†’        "${operations.joinToString(", ")}(${followedBy.joinToString(";")})"
 42â†’}
 43â†’
 44â†’// TODO: O(size of the resulting parser ^ 2), but can be O(size of the resulting parser)
 45â†’internal fun <T> List<ParserStructure<T>>.concat(): ParserStructure<T> {
 46â†’    fun <T> ParserStructure<T>.append(other: ParserStructure<T>): ParserStructure<T> = if (followedBy.isEmpty()) {
 47â†’        ParserStructure(operations + other.operations, other.followedBy)
 48â†’    } else {
 49â†’        ParserStructure(operations, followedBy.map { it.append(other) })
 50â†’    }
 51â†’    fun <T> ParserStructure<T>.simplify(): ParserStructure<T> {
 52â†’        val newOperations = mutableListOf<ParserOperation<T>>()
 53â†’        var currentNumberSpan: MutableList<NumberConsumer<T>>? = null
 54â†’        // joining together the number consumers in this parser before the first alternative
 55â†’        for (op in operations) {
 56â†’            if (op is NumberSpanParserOperation) {
 57â†’                if (currentNumberSpan != null) {
 58â†’                    currentNumberSpan.addAll(op.consumers)
 59â†’                } else {
 60â†’                    currentNumberSpan = op.consumers.toMutableList()
 61â†’                }
 62â†’            } else {
 63â†’                if (currentNumberSpan != null) {
 64â†’                    newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 65â†’                    currentNumberSpan = null
 66â†’                }
 67â†’                newOperations.add(op)
 68â†’            }
 69â†’        }
 70â†’        val mergedTails = followedBy.flatMap {
 71â†’            val simplified = it.simplify()
 72â†’            // parser `ParserStructure(emptyList(), p)` is equivalent to `p`,
 73â†’            // unless `p` is empty. For example, ((a|b)|(c|d)) is equivalent to (a|b|c|d).
 74â†’            // As a special case, `ParserStructure(emptyList(), emptyList())` represents a parser that recognizes an empty
 75â†’            // string. For example, (|a|b) is not equivalent to (a|b).
 76â†’            if (simplified.operations.isEmpty())
 77â†’                simplified.followedBy.ifEmpty { listOf(simplified) }
 78â†’            else
 79â†’                listOf(simplified)
 80â†’        }
 81â†’        return if (currentNumberSpan == null) {
 82â†’            // the last operation was not a number span, or it was a number span that we are allowed to interrupt
 83â†’            ParserStructure(newOperations, mergedTails)
 84â†’        } else if (mergedTails.none {
 85â†’                it.operations.firstOrNull()?.let { it is NumberSpanParserOperation } == true
 86â†’            }) {
 87â†’            // the last operation was a number span, but there are no alternatives that start with a number span.
 88â†’            newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 89â†’            ParserStructure(newOperations, mergedTails)
 90â†’        } else {
 91â†’            val newTails = mergedTails.map {
 92â†’                when (val firstOperation = it.operations.firstOrNull()) {
 93â†’                    is NumberSpanParserOperation -> {
 94â†’                        ParserStructure(
 95â†’                            listOf(NumberSpanParserOperation(currentNumberSpan + firstOperation.consumers)) + it.operations.drop(
 96â†’                                1
 97â†’                            ),
 98â†’                            it.followedBy
 99â†’                        )
100â†’                    }
101â†’
102â†’                    null -> ParserStructure(
103â†’                        listOf(NumberSpanParserOperation(currentNumberSpan)),
104â†’                        it.followedBy
105â†’                    )
106â†’
107â†’                    else -> ParserStructure(
108â†’                        listOf(NumberSpanParserOperation(currentNumberSpan)) + it.operations,
109â†’                        it.followedBy
110â†’                    )
111â†’                }
112â†’            }
113â†’            ParserStructure(newOperations, newTails)
114â†’        }
115â†’    }
116â†’    val naiveParser = foldRight(ParserStructure<T>(emptyList(), emptyList())) { parser, acc -> parser.append(acc) }
117â†’    return naiveParser.simplify()
118â†’}
119â†’
120â†’internal interface Copyable<Self> {
121â†’    fun copy(): Self
122â†’}
123â†’
124â†’@JvmInline
125â†’internal value class Parser<Output: Copyable<Output>>(
126â†’    private val commands: ParserStructure<Output>
127â†’) {
128â†’    /**
129â†’     * [startIndex] is the index of the first character that is not yet consumed.
130â†’     *
131â†’     * [allowDanglingInput] determines whether the match is only successful if the whole string after [startIndex]
132â†’     * is consumed.
133â†’     *
134â†’     * [onSuccess] is invoked as soon as some parsing attempt succeeds.
135â†’     * [onError] is invoked when some parsing attempt fails.
136â†’     */
137â†’    // Would be a great place to use the `Flow` from `kotlinx.coroutines` here instead of `onSuccess` and
138â†’    // `onError`, but alas.
139â†’    private inline fun parse(
140â†’        input: CharSequence,
141â†’        startIndex: Int,
142â†’        initialContainer: Output,
143â†’        allowDanglingInput: Boolean,
144â†’        onError: (ParseError) -> Unit,
145â†’        onSuccess: (Int, Output) -> Unit
146â†’    ) {
147â†’        val parseOptions = mutableListOf(ParserState(initialContainer, commands, startIndex))
148â†’        iterate_over_alternatives@while (true) {
149â†’            val state = parseOptions.removeLastOrNull() ?: break
150â†’            val output = state.output.copy()
151â†’            var inputPosition = state.inputPosition
152â†’            val parserStructure = state.parserStructure
153â†’            run parse_one_alternative@{
154â†’                for (ix in parserStructure.operations.indices) {
155â†’                    parserStructure.operations[ix].consume(output, input, inputPosition).match(
156â†’                        { inputPosition = it },
157â†’                        {
158â†’                            onError(it)
159â†’                            return@parse_one_alternative // continue@iterate_over_alternatives, if that were supported
160â†’                        }
161â†’                    )
162â†’                }
163â†’                if (parserStructure.followedBy.isEmpty()) {
164â†’                    if (allowDanglingInput || inputPosition == input.length) {
165â†’                        onSuccess(inputPosition, output)
166â†’                    } else {
167â†’                        onError(ParseError(inputPosition) { "There is more input to consume" })
168â†’                    }
169â†’                } else {
170â†’                    for (ix in parserStructure.followedBy.indices.reversed()) {
171â†’                        parseOptions.add(ParserState(output, parserStructure.followedBy[ix], inputPosition))
172â†’                    }
173â†’                }
174â†’            }
175â†’        }
176â†’    }
177â†’
178â†’    fun match(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output {
179â†’        val errors = mutableListOf<ParseError>()
180â†’        parse(input, startIndex, initialContainer, allowDanglingInput = false, { errors.add(it) }, { _, out -> return@match out })
181â†’        errors.sortByDescending { it.position }
182â†’        // `errors` can not be empty because each parser will have (successes + failures) >= 1, and here, successes == 0
183â†’        ParseException(errors.first()).let {
184â†’            for (error in errors.drop(1)) {
185â†’                it.addSuppressed(ParseException(error))
186â†’            }
187â†’            throw it
188â†’        }
189â†’    }
190â†’
191â†’    fun matchOrNull(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output? {
192â†’        parse(input, startIndex, initialContainer, allowDanglingInput = false, { }, { _, out -> return@matchOrNull out })
193â†’        return null
194â†’    }
195â†’
196â†’    private class ParserState<Output>(
197â†’        val output: Output,
198â†’        val parserStructure: ParserStructure<Output>,
199â†’        val inputPosition: Int,
200â†’    )
201â†’}
202â†’
203â†’internal class ParseException(error: ParseError) : Exception("Position ${error.position}: ${error.message()}")
