165â†’                            for (field in fields) {
166â†’                                field.assignDefault(it)
167â†’                            }
168â†’                        }
169â†’                    ),
170â†’                    emptyList()
171â†’                )
172â†’            ).concat()
173â†’        )
174â†’    )
175â†’
176â†’    override fun formatter(): FormatterStructure<T> {
177â†’        val formatter = format.formatter()
178â†’        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179â†’        return ConditionalFormatter(
180â†’            listOf(
181â†’                predicate::test to ConstantStringFormatterStructure(onZero),
182â†’                Truth::test to formatter
183â†’            )
184â†’        )
185â†’    }
