120â†’internal interface Copyable<Self> {
121â†’    fun copy(): Self
122â†’}
123â†’
124â†’@JvmInline
125â†’internal value class Parser<Output: Copyable<Output>>(
126â†’    private val commands: ParserStructure<Output>
127â†’) {
128â†’    /**
129â†’     * [startIndex] is the index of the first character that is not yet consumed.
130â†’     *
131â†’     * [allowDanglingInput] determines whether the match is only successful if the whole string after [startIndex]
132â†’     * is consumed.
133â†’     *
134â†’     * [onSuccess] is invoked as soon as some parsing attempt succeeds.
135â†’     * [onError] is invoked when some parsing attempt fails.
136â†’     */
137â†’    // Would be a great place to use the `Flow` from `kotlinx.coroutines` here instead of `onSuccess` and
138â†’    // `onError`, but alas.
139â†’    private inline fun parse(
140â†’        input: CharSequence,
141â†’        startIndex: Int,
142â†’        initialContainer: Output,
143â†’        allowDanglingInput: Boolean,
144â†’        onError: (ParseError) -> Unit,
145â†’        onSuccess: (Int, Output) -> Unit
146â†’    ) {
147â†’        val parseOptions = mutableListOf(ParserState(initialContainer, commands, startIndex))
148â†’        iterate_over_alternatives@while (true) {
149â†’            val state = parseOptions.removeLastOrNull() ?: break
150â†’            val output = state.output.copy()
151â†’            var inputPosition = state.inputPosition
152â†’            val parserStructure = state.parserStructure
153â†’            run parse_one_alternative@{
154â†’                for (ix in parserStructure.operations.indices) {
155â†’                    parserStructure.operations[ix].consume(output, input, inputPosition).match(
156â†’                        { inputPosition = it },
157â†’                        {
158â†’                            onError(it)
159â†’                            return@parse_one_alternative // continue@iterate_over_alternatives, if that were supported
160â†’                        }
161â†’                    )
162â†’                }
163â†’                if (parserStructure.followedBy.isEmpty()) {
164â†’                    if (allowDanglingInput || inputPosition == input.length) {
165â†’                        onSuccess(inputPosition, output)
166â†’                    } else {
167â†’                        onError(ParseError(inputPosition) { "There is more input to consume" })
168â†’                    }
169â†’                } else {
170â†’                    for (ix in parserStructure.followedBy.indices.reversed()) {
171â†’                        parseOptions.add(ParserState(output, parserStructure.followedBy[ix], inputPosition))
172â†’                    }
173â†’                }
174â†’            }
175â†’        }
176â†’    }
177â†’
178â†’    fun match(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output {
179â†’        val errors = mutableListOf<ParseError>()
180â†’        parse(input, startIndex, initialContainer, allowDanglingInput = false, { errors.add(it) }, { _, out -> return@match out })
181â†’        errors.sortByDescending { it.position }
182â†’        // `errors` can not be empty because each parser will have (successes + failures) >= 1, and here, successes == 0
183â†’        ParseException(errors.first()).let {
184â†’            for (error in errors.drop(1)) {
185â†’                it.addSuppressed(ParseException(error))
186â†’            }
187â†’            throw it
188â†’        }
189â†’    }
190â†’
191â†’    fun matchOrNull(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output? {
192â†’        parse(input, startIndex, initialContainer, allowDanglingInput = false, { }, { _, out -> return@matchOrNull out })
193â†’        return null
194â†’    }
195â†’
196â†’    private class ParserState<Output>(
197â†’        val output: Output,
198â†’        val parserStructure: ParserStructure<Output>,
199â†’        val inputPosition: Int,
200â†’    )
201â†’}
